import{_ as e,c as a,o as i,a2 as l}from"./chunks/framework.DdOM6S6U.js";const m=JSON.parse('{"title":"Filepond - File Input Component","description":"","frontmatter":{"outline":"deep","sidebarPos":5},"headers":[],"relativePath":"guide/components/input-filepond.md","filePath":"guide/components/input-filepond.md","lastUpdated":1735557979000}'),o={name:"guide/components/input-filepond.md"},s=l('<h1 id="filepond-file-input-component" tabindex="-1">Filepond - File Input Component <a class="header-anchor" href="#filepond-file-input-component" aria-label="Permalink to &quot;Filepond - File Input Component&quot;">​</a></h1><p><code>FilePond</code> is a JavaScript library that provides smooth drag-and-drop file uploading. By implementing the FilePond Vue component for image and file uploads, <code>Modularity</code> offers users easily implementable, configurable, and versatile file processing functionality.</p><div class="tip custom-block"><p class="custom-block-title">One to Many Polymorphic Bounding</p><p>There is another way to process files/ medias with modularity, that is using file/media libraries. Unlike using file/media library, <code>FilePond with Modularity</code> offers <code>one to many</code> bounding between models and files.</p></div><h2 id="feature-implementation-road-map" tabindex="-1">Feature Implementation Road Map <a class="header-anchor" href="#feature-implementation-road-map" aria-label="Permalink to &quot;Feature Implementation Road Map&quot;">​</a></h2><h3 id="trait-implementation" tabindex="-1">Trait Implementation <a class="header-anchor" href="#trait-implementation" aria-label="Permalink to &quot;Trait Implementation&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Add <code>HasFileponds</code> and <code>FilepondsTrait</code> to your route&#39;s model and repository respectively to implement file processing mechanism.</p></div><p>In order to effectively use the FilePond component and its functionalities on the desired model, you need to add two traits: <code>FilepondsTrait and HasFileponds</code>. The <code>FilepondsTrait</code> should be implemented in the <code>repository</code>, interacting with the module&#39;s data storage mechanism and handling the file storage process. Conversely, the <code>HasFileponds</code> trait should be implemented in the <code>model</code>, introducing relationship and casting methods to the parent model to bind files.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Modularity serves most of the functionalities over traits. See <a href="/guide/generics/file-storage-with-filepond">File Storage with Filepond</a> for the full implementation guide.</p></div><h3 id="route-config-input-configuration" tabindex="-1">Route Config - Input Configuration <a class="header-anchor" href="#route-config-input-configuration" aria-label="Permalink to &quot;Route Config - Input Configuration&quot;">​</a></h3><p>Route&#39;s configuration files allow you to configure input component and its metadata. After adding given traits above, define <code>filepond</code> component to route&#39;s input array to use <code>FilePond</code> vue component.</p><br><h4 id="simple-usage" tabindex="-1">Simple Usage <a class="header-anchor" href="#simple-usage" aria-label="Permalink to &quot;Simple Usage&quot;">​</a></h4><p><code>Type</code> parameter should be given as <code>filepond</code></p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &#39;web_company&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          &#39;name&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;WebCompany&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          &#39;headline&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Web Companies&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          &#39;url&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;web-companies&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          &#39;route_name&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;web_company&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          &#39;icon&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;$submodule&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          &#39;table_options&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              //..code</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          ],</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          &#39;headers&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              //..code</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          ],</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          &#39;inputs&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              //..code</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">              [</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">                  &#39;name&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;avatar&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">                  &#39;label&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Avatar&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">                  &#39;type&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;filepond&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">                  &#39;_rules&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;sometimes|required|min:3&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">              ],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          ],</span></span></code></pre></div><h3 id="advanced-options-and-avaliable-props" tabindex="-1">Advanced options and avaliable props <a class="header-anchor" href="#advanced-options-and-avaliable-props" aria-label="Permalink to &quot;Advanced options and avaliable props&quot;">​</a></h3><br><h4 id="accepted-file-types" tabindex="-1"><code>accepted-file-types</code> <a class="header-anchor" href="#accepted-file-types" aria-label="Permalink to &quot;`accepted-file-types`&quot;">​</a></h4><p>Controlls the allowable file types to be uploaded to your model. For an example, Can be defined as <code>file/pdf, image/*</code> to allow all image types and pdf types only. Different types should be seperated with comma <code>,</code> .</p><ul><li><code>Input Type:</code> <code>String</code></li><li><code>Default:</code> <code>file/*, image/*</code> (all types of files and image types)</li></ul><br><h4 id="allow-multiple" tabindex="-1"><code>allow-multiple</code> <a class="header-anchor" href="#allow-multiple" aria-label="Permalink to &quot;`allow-multiple`&quot;">​</a></h4><p>Configures multiple file uploading functionality allowance.</p><ul><li><code>Input Type:</code> <code>Boolean</code></li><li><code>Variance:</code> <code>true|false|null</code></li><li><code>Default:</code> <code>true</code></li></ul><br><h4 id="max-files" tabindex="-1"><code>max-files</code> <a class="header-anchor" href="#max-files" aria-label="Permalink to &quot;`max-files`&quot;">​</a></h4><p>Controlls the maximum number of files can be upload.</p><ul><li><code>Input Type:</code> <code>String|Number|null</code></li><li><code>Default:</code> <code>null</code> (unlimited)</li></ul><br><h4 id="allow-drop" tabindex="-1"><code>allow-drop</code> <a class="header-anchor" href="#allow-drop" aria-label="Permalink to &quot;`allow-drop`&quot;">​</a></h4><p>Enables or disables the drag and drop functionality.</p><ul><li><code>Input Type:</code> <code>Boolean</code></li><li><code>Variance:</code> <code>true|false|null</code></li><li><code>Default:</code> <code>true</code></li></ul><br><h4 id="allow-browse" tabindex="-1"><code>allow-browse</code> <a class="header-anchor" href="#allow-browse" aria-label="Permalink to &quot;`allow-browse`&quot;">​</a></h4><p>Enables or disables the file browser functionality.</p><ul><li><code>Input Type:</code> <code>Boolean</code></li><li><code>Variance:</code> <code>true|false|null</code></li><li><code>Default:</code> <code>true</code></li></ul><br><h4 id="allow-replace" tabindex="-1"><code>allow-replace</code> <a class="header-anchor" href="#allow-replace" aria-label="Permalink to &quot;`allow-replace`&quot;">​</a></h4><p>Allow drop to replace a file, only works when <code>allow-multiple</code> is <code>false</code></p><ul><li><code>Input Type:</code> <code>Boolean</code></li><li><code>Variance:</code> <code>true|false|null</code></li><li><code>Default:</code> <code>true</code></li></ul><br><h4 id="allow-remove" tabindex="-1"><code>allow-remove</code> <a class="header-anchor" href="#allow-remove" aria-label="Permalink to &quot;`allow-remove`&quot;">​</a></h4><p>Allow remove a file, or hide and disable the remove button.</p><ul><li><code>Input Type:</code> <code>Boolean</code></li><li><code>Variance:</code> <code>true|false|null</code></li><li><code>Default:</code> <code>true</code></li></ul><br><h4 id="allow-process" tabindex="-1"><code>allow-process</code> <a class="header-anchor" href="#allow-process" aria-label="Permalink to &quot;`allow-process`&quot;">​</a></h4><p>Enable or disable the process button.</p><ul><li><code>Input Type:</code> <code>Boolean</code></li><li><code>Variance:</code> <code>true|false|null</code></li><li><code>Default:</code> <code>true</code></li></ul><br><h4 id="allow-image-preview" tabindex="-1"><code>allow-image-preview</code> <a class="header-anchor" href="#allow-image-preview" aria-label="Permalink to &quot;`allow-image-preview`&quot;">​</a></h4><p>Configures the image preview will be shown or not.</p><ul><li><code>Input Type:</code> <code>Boolean</code></li><li><code>Variance:</code> <code>true|false|null</code></li><li><code>Default:</code> <code>false</code></li></ul><br><h4 id="drop-on-page" tabindex="-1"><code>drop-on-page</code> <a class="header-anchor" href="#drop-on-page" aria-label="Permalink to &quot;`drop-on-page`&quot;">​</a></h4><p>FilePond will catch all files dropped on the webpage</p><ul><li><code>Input Type:</code> <code>Boolean</code></li><li><code>Variance:</code> <code>true|false|null</code></li><li><code>Default:</code> <code>false</code></li></ul><br><h4 id="drop-on-element" tabindex="-1"><code>drop-on-element</code> <a class="header-anchor" href="#drop-on-element" aria-label="Permalink to &quot;`drop-on-element`&quot;">​</a></h4><p>Require drop on the FilePond element itself to catch the file.</p><ul><li><code>Input Type:</code> <code>Boolean</code></li><li><code>Variance:</code> <code>true|false|null</code></li><li><code>Default:</code> <code>true</code></li></ul><br><h4 id="drop-validation" tabindex="-1"><code>drop-validation</code> <a class="header-anchor" href="#drop-validation" aria-label="Permalink to &quot;`drop-validation`&quot;">​</a></h4><p>When enabled, files are validated before they are dropped. A file is not added when it&#39;s invalid.</p><ul><li><code>Input Type:</code> <code>Boolean</code></li><li><code>Variance:</code> <code>true|false|null</code></li><li><code>Default:</code> <code>false</code></li></ul><br>',64),n=[s];function t(d,p,c,r,h,u){return i(),a("div",null,n)}const f=e(o,[["render",t]]);export{m as __pageData,f as default};
